 49→/**
 50→ * Limite simple 100 req/min par cle.
 51→ */
 52→export const enforceRateLimit = (key: string, maxPerMinute = 100): void => {
 53→  const now = Date.now();
 54→  const existing = requestBuckets.get(key);
 55→  if (!existing || now >= existing.resetAt) {
 56→    requestBuckets.set(key, {
 57→      count: 1,
 58→      resetAt: now + 60_000,
 59→    });
 60→    return;
 61→  }
 62→  if (existing.count >= maxPerMinute) {
 63→    throw new Error('Rate limit depasse');
 64→  }
 65→  existing.count += 1;
 66→  requestBuckets.set(key, existing);
 67→};
