 69→/**
 70→ * Hash SHA-256 deterministe (hex).
 71→ */
 72→export const sha256Hex = async (value: string): Promise<string> => {
 73→  const data = new TextEncoder().encode(value);
 74→  const hash = await crypto.subtle.digest('SHA-256', data);
 75→  const bytes = Array.from(new Uint8Array(hash));
 76→  return bytes.map((byte) => byte.toString(16).padStart(2, '0')).join('');
 77→};
