 1→import { headers } from 'next/headers';
 2→import { NextResponse } from 'next/server';
 3→import { stripe, getPlanFromPriceId } from '@/lib/stripe';
 4→import { createClient } from '@supabase/supabase-js';
 5→import Stripe from 'stripe';
 6→
 7→export async function POST(req: Request) {
 8→  // Client Admin pour bypasser RLS (lazy init to avoid build-time env var errors)
 9→  const supabaseAdmin = createClient(
10→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
11→    process.env.SUPABASE_SERVICE_ROLE_KEY!
12→  );
13→
14→  const body = await req.text();
15→  const signature = headers().get('Stripe-Signature') as string;
16→
17→  let event: Stripe.Event;
18→
19→  try {
20→    event = stripe.webhooks.constructEvent(
21→      body,
22→      signature,
23→      process.env.STRIPE_WEBHOOK_SECRET!
24→    );
25→  } catch (error) {
26→    return new NextResponse('Webhook error', { status: 400 });
27→  }
28→
29→  // Idempotence
30→  const { data: processed } = await supabaseAdmin
31→    .from('stripe_events_processed')
32→    .select('id')
33→    .eq('event_id', event.id)
34→    .single();
35→
36→  if (processed) return new NextResponse('Event already processed', { status: 200 });
37→
38→  const session = event.data.object as Stripe.Checkout.Session | Stripe.Subscription;
39→
40→  // 1. Gestion des événements
41→  if (event.type === 'checkout.session.completed') {
42→    const checkoutSession = session as Stripe.Checkout.Session;
43→    const workspaceId = checkoutSession.metadata?.workspaceId;
44→    const subscriptionId = checkoutSession.subscription as string;
45→
46→    if (workspaceId) {
47→      await supabaseAdmin.from('workspaces').update({
48→        stripe_subscription_id: subscriptionId,
49→        stripe_customer_id: checkoutSession.customer as string,
50→      }).eq('id', workspaceId);
51→    }
52→  }
53→
54→  if (event.type === 'customer.subscription.created' || event.type === 'customer.subscription.updated') {
55→    const subscription = session as Stripe.Subscription;
56→    const workspaceId = subscription.metadata?.workspaceId;
57→    
58→    const priceId = subscription.items.data[0].price.id;
59→    const planName = getPlanFromPriceId(priceId);
60→
61→    if (workspaceId) {
62→      await supabaseAdmin.from('workspaces').update({
63→        plan: planName,
64→        plan_status: subscription.status,
65→        current_period_end: new Date(subscription.current_period_end * 1000).toISOString(),
66→      }).eq('id', workspaceId);
67→    }
68→  }
69→
70→  if (event.type === 'customer.subscription.deleted') {
71→    const subscription = session as Stripe.Subscription;
72→    const workspaceId = subscription.metadata?.workspaceId;
73→
74→    if (workspaceId) {
75→      await supabaseAdmin.from('workspaces').update({
76→        plan: 'starter',
77→        plan_status: 'canceled',
78→        stripe_subscription_id: null
79→      }).eq('id', workspaceId);
80→    }
81→  }
82→
83→  // 2. Enregistrer l'event
84→  await supabaseAdmin.from('stripe_events_processed').insert({
85→    event_id: event.id,
86→    type: event.type
87→  });
88→
89→  return new NextResponse(null, { status: 200 });
90→}

 1→import { NextResponse } from 'next/server';
 2→import { createClient } from '@/lib/supabase/server';
 3→import { stripe, PLANS } from '@/lib/stripe';
 4→
 5→export async function POST(req: Request) {
 6→  const supabase = createClient();
 7→  const { data: { user } } = await supabase.auth.getUser();
 8→
 9→  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
10→
11→  const body = await req.json();
12→  const { workspaceId, plan } = body; 
13→
14→  if (!workspaceId) return NextResponse.json({ error: 'Workspace ID required' }, { status: 400 });
15→
16→  // 1. Vérifier le rôle (Owner/Admin seulement)
17→  const { data: membership } = await supabase
18→    .from('workspace_users')
19→    .select('role')
20→    .eq('workspace_id', workspaceId)
21→    .eq('user_id', user.id)
22→    .single();
23→
24→  if (!membership || !['owner', 'admin'].includes(membership.role)) {
25→    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
26→  }
27→
28→  // 2. Récupérer le customer ID existant s'il y en a un
29→  const { data: workspace } = await supabase
30→    .from('workspaces')
31→    .select('stripe_customer_id')
32→    .eq('id', workspaceId)
33→    .single();
34→
35→  let customerId = workspace?.stripe_customer_id;
36→
37→  // 3. Créer le Customer Stripe si inexistant
38→  if (!customerId) {
39→    const customer = await stripe.customers.create({
40→      email: user.email,
41→      metadata: { workspaceId: workspaceId }
42→    });
43→    customerId = customer.id;
44→    // Mise à jour DB
45→    await supabase.from('workspaces').update({ stripe_customer_id: customerId }).eq('id', workspaceId);
46→  }
47→
48→  // 4. Créer la session
49→  const priceId = PLANS[plan as keyof typeof PLANS];
50→  
51→  const session = await stripe.checkout.sessions.create({
52→    customer: customerId,
53→    line_items: [{ price: priceId, quantity: 1 }],
54→    mode: 'subscription',
55→    success_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing?success=true`,
56→    cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing?canceled=true`,
57→    subscription_data: {
58→      metadata: { workspaceId: workspaceId }
59→    },
60→    metadata: { workspaceId: workspaceId }
61→  });
62→
63→  return NextResponse.json({ url: session.url });
64→}

