  1→import { corsHeaders, createAdminClient, enforceRateLimit, jsonResponse, logAutomationEvent, parseJsonBody, sha256Hex } from '../_shared/common.ts';
  2→
  3→interface IngestPayload {
  4→  sector: string;
  5→  source: string;
  6→  data: Array<Record<string, unknown>>;
  7→}
  8→
  9→const normalize = (value: unknown): string => String(value ?? '').trim().toLowerCase();
 10→
 11→/**
 12→ * Point d'entree ingestion n8n -> LeadRadar.
 13→ */
 14→Deno.serve(async (request: Request) => {
 15→  if (request.method === 'OPTIONS') {
 16→    return new Response('ok', { headers: corsHeaders });
 17→  }
 18→
 19→  const ip = request.headers.get('x-forwarded-for') ?? 'anonymous';
 20→  try {
 21→    enforceRateLimit(`ingest:${ip}`, 100);
 22→
 23→    if (request.method !== 'POST') {
 24→      return jsonResponse({ error: 'Method not allowed' }, 405);
 25→    }
 26→
 27→    const payload = await parseJsonBody<IngestPayload>(request);
 28→    if (!payload.sector || !payload.source || !Array.isArray(payload.data)) {
 29→      return jsonResponse({ error: 'Payload invalide' }, 400);
 30→    }
 31→
 32→    const admin = createAdminClient();
 33→    await logAutomationEvent('scan_started', {
 34→      sector: payload.sector,
 35→      source: payload.source,
 36→      total_items: payload.data.length,
 37→    });
 38→
 39→    const { data: sourceRow } = await admin
 40→      .from('sources')
 41→      .select('id')
 42→      .eq('sector_id', payload.sector)
 43→      .ilike('name', `%${payload.source}%`)
 44→      .limit(1)
 45→      .maybeSingle<{ id: string }>();
 46→
 47→    let ingested = 0;
 48→    let duplicates = 0;
 49→    let errors = 0;
 50→
 51→    const supabaseUrl = Deno.env.get('SUPABASE_URL');
 52→    const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');
 53→    if (!supabaseUrl || !serviceRoleKey) {
 54→      throw new Error('Variables Supabase manquantes');
 55→    }
 56→
 57→    for (const item of payload.data) {
 58→      try {
 59→        const dedupBase = [
 60→          normalize(item.name ?? item.title ?? item.label),
 61→          normalize(item.location ?? item.city ?? item.address),
 62→          normalize(item.date ?? item.detected_at ?? item.created_at),
 63→          normalize(payload.source),
 64→          normalize(payload.sector),
 65→        ].join('|');
 66→        const dedupHash = await sha256Hex(dedupBase);
 67→
 68→        const { data: existing } = await admin
 69→          .from('prospects')
 70→          .select('id')
 71→          .eq('dedup_hash', dedupHash)
 72→          .limit(1)
 73→          .maybeSingle<{ id: string }>();
 74→        if (existing?.id) {
 75→          duplicates += 1;
 76→          continue;
 77→        }
 78→
 79→        const controller = new AbortController();
 80→        const timeoutId = setTimeout(() => controller.abort(), 30_000);
 81→        const response = await fetch(`${supabaseUrl}/functions/v1/analyze`, {
 82→          method: 'POST',
 83→          signal: controller.signal,
 84→          headers: {
 85→            Authorization: `Bearer ${serviceRoleKey}`,
 86→            apikey: serviceRoleKey,
 87→            'Content-Type': 'application/json',
 88→          },
 89→          body: JSON.stringify({
 90→            sector: payload.sector,
 91→            source: payload.source,
 92→            source_id: sourceRow?.id ?? null,
 93→            raw_data: item,
 94→            dedup_hash: dedupHash,
 95→          }),
 96→        });
 97→        clearTimeout(timeoutId);
 98→
 99→        if (!response.ok) {
100→          errors += 1;
101→          const details = await response.text();
102→          await logAutomationEvent('error', {
103→            stage: 'ingest->analyze',
104→            reason: details,
105→          }, sourceRow?.id ?? null);
106→          continue;
107→        }
108→        ingested += 1;
109→      } catch (itemError) {
110→        errors += 1;
111→        await logAutomationEvent('error', {
112→          stage: 'ingest-item',
113→          reason: itemError instanceof Error ? itemError.message : 'unknown',
114→        }, sourceRow?.id ?? null);
115→      }
116→    }
117→
118→    await logAutomationEvent('scan_completed', {
119→      sector: payload.sector,
120→      source: payload.source,
121→      ingested,
122→      duplicates,
123→      errors,
124→    }, sourceRow?.id ?? null);
125→
126→    return jsonResponse({ ingested, duplicates, errors });
127→  } catch (error) {
128→    await logAutomationEvent('error', {
129→      stage: 'ingest',
130→      reason: error instanceof Error ? error.message : 'unknown',
131→    });
132→    return jsonResponse({ error: error instanceof Error ? error.message : 'Erreur ingest' }, 500);
133→  }
134→});
