 20→const generateHex = (length: number): string => {
 21→  const chars = '0123456789abcdef';
 22→  let result = '';
 23→  for (let i = 0; i < length; i++) {
 24→    result += chars[Math.floor(Math.random() * chars.length)];
 25→  }
 26→  return result;
 27→};
