 44→export const createApiKey = (name: string): ApiKey => {
 45→  const newKey: ApiKey = {
 46→    id: generateId(),
 47→    name,
 48→    key: `cb_live_${generateHex(32)}`,
 49→    createdAt: new Date().toISOString(),
 50→    status: 'active',
 51→  };
 52→  const keys = getApiKeys();
 53→  keys.unshift(newKey);
 54→  saveApiKeys(keys);
