 65→export const regenerateApiKey = (id: string): ApiKey | null => {
 66→  const keys = getApiKeys();
 67→  const index = keys.findIndex((k) => k.id === id);
 68→  if (index === -1) return null;
 69→  const updated: ApiKey = {
 70→    ...keys[index],
 71→    key: `cb_live_${generateHex(32)}`,
 72→    createdAt: new Date().toISOString(),
 73→    status: 'active',
 74→  };
 75→  keys[index] = updated;
 76→  saveApiKeys(keys);
 77→  return updated;
 78→};
