15→  const [error, setError] = useState<string | null>(null);
16→
17→  /**
18→   * Lance un checkout Stripe pour un pack de credits.
19→   */
20→  const buyPack = async (packId: string): Promise<void> => {
21→    if (!isSupabaseConfigured) {
22→      setError('Mode demo: achat de credits indisponible sans configuration Supabase.');
23→      return;
24→    }
25→    try {
26→      setLoadingPackId(packId);
27→      setError(null);
28→      const { data, error: invokeError } = await supabase.functions.invoke('create-checkout', {
29→        body: {
30→          user_id: userId,
31→          pack_id: packId,
32→        },
33→      });
34→      if (invokeError) {
35→        throw invokeError;
36→      }
37→      const checkoutUrl = String((data as { url?: string } | null)?.url ?? '');
38→      if (!checkoutUrl) {
39→        throw new Error('URL checkout manquante');
40→      }
41→      window.location.href = checkoutUrl;
42→    } catch (caughtError) {
43→      const message = caughtError instanceof Error ? caughtError.message : 'Achat credits impossible';
44→      setError(message);
45→    } finally {
46→      setLoadingPackId(null);
47→    }
