  1→import Stripe from 'https://esm.sh/stripe@15.12.0?target=denonext';
  2→import { corsHeaders, createAdminClient, enforceRateLimit, jsonResponse, parseJsonBody } from '../_shared/common.ts';
  3→
  4→interface CheckoutPayload {
  5→  price_id?: string;
  6→  pack_id?: 'pack_20' | 'pack_50' | 'pack_120' | 'pack_300';
  7→  user_id: string;
  8→  purchase_origin?: 'manual' | 'auto';
  9→}
 10→
 11→const stripeSecretKey = Deno.env.get('STRIPE_SECRET_KEY');
 12→if (!stripeSecretKey) {
 13→  throw new Error('STRIPE_SECRET_KEY manquante');
 14→}
 15→
 16→const stripe = new Stripe(stripeSecretKey, {
 17→  apiVersion: '2024-04-10',
 18→});
 19→
 20→interface CreditPack {
 21→  id: 'pack_20' | 'pack_50' | 'pack_120' | 'pack_300';
 22→  priceId: string;
 23→  creditsBase: number;
 24→  creditsBonus: number;
 25→}
 26→
 27→const getConfiguredPacks = (): CreditPack[] =>
 28→  [
 29→    {
 30→      id: 'pack_20',
 31→      priceId: Deno.env.get('STRIPE_PRICE_CREDITS_20') ?? '',
 32→      creditsBase: 20,
 33→      creditsBonus: 0,
 34→    },
 35→    {
 36→      id: 'pack_50',
 37→      priceId: Deno.env.get('STRIPE_PRICE_CREDITS_50') ?? '',
 38→      creditsBase: 50,
 39→      creditsBonus: 5,
 40→    },
 41→    {
 42→      id: 'pack_120',
 43→      priceId: Deno.env.get('STRIPE_PRICE_CREDITS_120') ?? '',
 44→      creditsBase: 120,
 45→      creditsBonus: 15,
 46→    },
 47→    {
 48→      id: 'pack_300',
 49→      priceId: Deno.env.get('STRIPE_PRICE_CREDITS_300') ?? '',
 50→      creditsBase: 300,
 51→      creditsBonus: 50,
 52→    },
 53→  ].filter((pack) => pack.priceId);
 54→
 55→const resolvePack = (payload: CheckoutPayload): CreditPack | null => {
 56→  const packs = getConfiguredPacks();
 57→  if (payload.pack_id) {
 58→    return packs.find((pack) => pack.id === payload.pack_id) ?? null;
 59→  }
 60→  if (payload.price_id) {
 61→    return packs.find((pack) => pack.priceId === payload.price_id) ?? null;
 62→  }
 63→  return packs.find((pack) => pack.id === 'pack_20') ?? null;
 64→};
