 66→/**
 67→ * Cree une session checkout Stripe pour achat cash de credits.
 68→ */
 69→Deno.serve(async (request: Request) => {
 70→  if (request.method === 'OPTIONS') {
 71→    return new Response('ok', { headers: corsHeaders });
 72→  }
 73→  const ip = request.headers.get('x-forwarded-for') ?? 'anonymous';
 74→  try {
 75→    enforceRateLimit(`checkout:${ip}`, 100);
 76→    if (request.method !== 'POST') {
 77→      return jsonResponse({ error: 'Method not allowed' }, 405);
 78→    }
 79→    const payload = await parseJsonBody<CheckoutPayload>(request);
 80→    if (!payload.user_id) {
 81→      return jsonResponse({ error: 'user_id requis' }, 400);
 82→    }
 83→
 84→    const admin = createAdminClient();
 85→    const { data: profile, error: profileError } = await admin
 86→      .from('profiles')
 87→      .select('id, email, full_name, stripe_customer_id')
 88→      .eq('id', payload.user_id)
 89→      .single<{
 90→        id: string;
 91→        email: string;
 92→        full_name: string | null;
 93→        stripe_customer_id: string | null;
 94→      }>();
 95→    if (profileError || !profile) {
 96→      throw new Error('Profil introuvable');
 97→    }
 98→
 99→    let customerId = profile.stripe_customer_id;
100→    if (!customerId) {
101→      const customer = await stripe.customers.create({
102→        email: profile.email,
103→        name: profile.full_name ?? undefined,
104→        metadata: { user_id: profile.id },
105→      });
106→      customerId = customer.id;
107→      await admin
108→        .from('profiles')
109→        .update({
110→          stripe_customer_id: customerId,
111→          updated_at: new Date().toISOString(),
112→        })
113→        .eq('id', profile.id);
114→    }
115→
116→    const selectedPack = resolvePack(payload);
117→    if (!selectedPack) {
118→      throw new Error('pack_id/price_id credits invalide ou non configure');
119→    }
120→
121→    const appUrl = Deno.env.get('APP_URL') ?? 'http://localhost:5173';
122→    const creditsTotal = selectedPack.creditsBase + selectedPack.creditsBonus;
123→    const checkoutSession = await stripe.checkout.sessions.create({
124→      customer: customerId,
125→      mode: 'payment',
126→      line_items: [{ price: selectedPack.priceId, quantity: 1 }],
127→      client_reference_id: profile.id,
128→      metadata: {
129→        user_id: profile.id,
130→        pack_id: selectedPack.id,
131→        credits_base: String(selectedPack.creditsBase),
132→        credits_bonus: String(selectedPack.creditsBonus),
133→        credits_total: String(creditsTotal),
134→        purchase_origin: payload.purchase_origin ?? 'manual',
135→      },
136→      payment_intent_data: {
137→        setup_future_usage: 'off_session',
138→      },
139→      success_url: `${appUrl}/reglages?checkout=success`,
140→      cancel_url: `${appUrl}/reglages?checkout=cancel`,
141→      allow_promotion_codes: true,
142→    });
143→
144→    return jsonResponse({
145→      url: checkoutSession.url,
146→      session_id: checkoutSession.id,
147→    });
148→  } catch (error) {
149→    return jsonResponse({ error: error instanceof Error ? error.message : 'Erreur checkout' }, 500);
150→  }
151→});
