  1→import Stripe from 'https://esm.sh/stripe@15.12.0?target=denonext';
  2→import { createAdminClient } from '../_shared/common.ts';
  3→
  4→const stripeSecretKey = Deno.env.get('STRIPE_SECRET_KEY');
  5→const webhookSecret = Deno.env.get('STRIPE_WEBHOOK_SECRET');
  6→
  7→if (!stripeSecretKey || !webhookSecret) {
  8→  throw new Error('STRIPE_SECRET_KEY/STRIPE_WEBHOOK_SECRET manquants');
  9→}
 10→
 11→const stripe = new Stripe(stripeSecretKey, {
 12→  apiVersion: '2024-04-10',
 13→});
 14→
 15→const priceToCredits = (priceId: string | null | undefined): number => {
 16→  const mapping: Record<string, number> = {
 17→    [Deno.env.get('STRIPE_PRICE_CREDITS_20') ?? '']: 20,
 18→    [Deno.env.get('STRIPE_PRICE_CREDITS_50') ?? '']: 55,
 19→    [Deno.env.get('STRIPE_PRICE_CREDITS_120') ?? '']: 135,
 20→    [Deno.env.get('STRIPE_PRICE_CREDITS_300') ?? '']: 350,
 21→  };
 22→  return mapping[priceId ?? ''] ?? 0;
 23→};
 24→
 25→/**
 26→ * Webhook Stripe pour crediter les comptes après paiement one-shot.
 27→ */
 28→Deno.serve(async (request: Request) => {
 29→  if (request.method !== 'POST') {
 30→    return new Response('Method not allowed', { status: 405 });
 31→  }
 32→
 33→  try {
 34→    const signature = request.headers.get('stripe-signature');
 35→    if (!signature) {
 36→      return new Response('Missing signature', { status: 400 });
 37→    }
 38→
 39→    const rawBody = await request.text();
 40→    const event = await stripe.webhooks.constructEventAsync(rawBody, signature, webhookSecret);
 41→    const admin = createAdminClient();
 42→
 43→    if (event.type === 'checkout.session.completed') {
 44→      const session = event.data.object as Stripe.Checkout.Session;
 45→      const checkoutSessionId = session.id;
 46→      const userId = session.client_reference_id ?? session.metadata?.user_id ?? null;
 47→      const customerId = typeof session.customer === 'string' ? session.customer : null;
 48→      const paymentIntentId = typeof session.payment_intent === 'string' ? session.payment_intent : null;
 49→      const totalAmountEur = session.amount_total ? session.amount_total / 100 : null;
 50→
 51→      if (!userId) {
 52→        return new Response(JSON.stringify({ received: true, ignored: 'missing_user_id' }), {
 53→          status: 200,
 54→          headers: { 'Content-Type': 'application/json' },
 55→        });
 56→      }
 57→
 58→      const { data: existingTx } = await admin
 59→        .from('credit_transactions')
 60→        .select('id')
 61→        .eq('stripe_checkout_session_id', checkoutSessionId)
 62→        .maybeSingle<{ id: string }>();
 63→      if (existingTx?.id) {
 64→        return new Response(JSON.stringify({ received: true, idempotent: true }), {
 65→          status: 200,
 66→          headers: { 'Content-Type': 'application/json' },
 67→        });
 68→      }
 69→
 70→      let creditsToAdd = Number(session.metadata?.credits_total ?? 0);
 71→      if (!Number.isFinite(creditsToAdd) || creditsToAdd <= 0) {
 72→        const lineItems = await stripe.checkout.sessions.listLineItems(checkoutSessionId, { limit: 5 });
 73→        creditsToAdd = lineItems.data.reduce((total, item) => {
 74→          const priceId = item.price?.id ?? null;
 75→          const qty = item.quantity ?? 1;
 76→          return total + priceToCredits(priceId) * qty;
 77→        }, 0);
 78→      }
 79→
 80→      if (creditsToAdd <= 0) {
 81→        throw new Error('Impossible de determiner le nombre de credits achetes');
 82→      }
 83→
 84→      const { data: profile, error: profileError } = await admin
 85→        .from('profiles')
 86→        .select('id, credits_balance, credits_total_purchased')
 87→        .eq('id', userId)
 88→        .single<{ id: string; credits_balance: number; credits_total_purchased: number }>();
 89→      if (profileError || !profile) {
 90→        throw new Error('Profil utilisateur introuvable');
 91→      }
 92→
 93→      const nextBalance = profile.credits_balance + creditsToAdd;
 94→      const nextPurchased = profile.credits_total_purchased + creditsToAdd;
 95→      const nowIso = new Date().toISOString();
 96→
 97→      await admin
 98→        .from('profiles')
 99→        .update({
100→          stripe_customer_id: customerId,
101→          credits_balance: nextBalance,
102→          credits_total_purchased: nextPurchased,
103→          updated_at: nowIso,
104→        })
105→        .eq('id', userId);
106→
107→      await admin.from('credit_transactions').insert({
108→        user_id: userId,
109→        transaction_type: 'purchase',
110→        credits_delta: creditsToAdd,
111→        credits_balance_after: nextBalance,
112→        amount_eur: totalAmountEur,
113→        stripe_checkout_session_id: checkoutSessionId,
114→        stripe_payment_intent_id: paymentIntentId,
115→        description: `Achat credits Stripe (${creditsToAdd})`,
116→        metadata_json: {
117→          event_id: event.id,
118→          pack_id: session.metadata?.pack_id ?? null,
119→        },
120→      });
121→
122→      await admin.from('notifications').insert({
123→        user_id: userId,
124→        prospect_id: null,
125→        type: 'credit_purchase',
126→        title: 'Credits ajoutes',
127→        body: `${creditsToAdd} credits ont ete ajoutes a votre portefeuille.`,
128→      });
129→    }
130→
131→    return new Response(JSON.stringify({ received: true }), {
132→      status: 200,
133→      headers: { 'Content-Type': 'application/json' },
134→    });
135→  } catch (error) {
136→    return new Response(error instanceof Error ? error.message : 'Webhook error', { status: 400 });
137→  }
138→});
